scripts.implementation:
# Enable BitLocker on all drives
try {
    $volumes = Get-BitLockerVolume | Where-Object { $_.ProtectionStatus -eq 'Off' }
    foreach ($vol in $volumes) {
        Enable-BitLocker -MountPoint $vol.MountPoint -EncryptionMethod Aes256 -SkipHardwareTest -RecoveryPasswordProtector | Out-Null
        Write-Output "BitLocker enabled on $($vol.MountPoint)"
    }
} catch { Write-Error $_.Exception.Message; exit 1 }

rollback.powershell:
# Rollback: Disable BitLocker on all drives
Get-BitLockerVolume | Where-Object { $_.ProtectionStatus -eq 'On' } | ForEach-Object {
    Disable-BitLocker -MountPoint $_.MountPoint
    Write-Output "BitLocker disabled on $($_.MountPoint)"
}

