scripts.detection:
# Exit 0 = no unquoted paths, Exit 1 = vulnerabilities found
$unquoted = Get-WmiObject Win32_Service | Where-Object {
    $_.PathName -notmatch '^"' -and $_.PathName -match ' ' -and $_.PathName -notmatch '^[A-Za-z]:\Windows\'
}
if ($unquoted.Count -eq 0) { exit 0 } else {
    $unquoted | Select-Object Name, PathName | ForEach-Object { Write-Output "UNQUOTED: $($_.Name) - $($_.PathName)" }
    exit 1
}

scripts.implementation:
# Fix unquoted service paths - wrap paths in quotes
$services = Get-WmiObject Win32_Service | Where-Object {
    $_.PathName -notmatch '^"' -and $_.PathName -match ' ' -and $_.PathName -notmatch '^[A-Za-z]:\Windows\'
}
foreach ($svc in $services) {
    try {
        $quotedPath = '"' + $svc.PathName + '"'
        Set-ItemProperty "HKLM:\SYSTEM\CurrentControlSet\Services\$($svc.Name)" -Name 'ImagePath' -Value $quotedPath
        Write-Output "Fixed: $($svc.Name)"
    } catch { Write-Output "Failed to fix: $($svc.Name) - $($_.Exception.Message)" }
}

